using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

// --- Data models ---

public class CustomerData
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4)] public string Churned { get; set; } = "";
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public string PredictedLabel { get; set; } = "";
    public float Probability { get; set; }
    public float Score { get; set; }
}

// --- Train and save the model ---

var mlContext = new MLContext(seed: 42);

var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
IDataView data = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

var pipeline = mlContext.Transforms.Conversion
        .MapValueToKey("Label", nameof(CustomerData.Churned))
    .Append(mlContext.Transforms.Categorical
        .OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        "RegionEncoded",
        nameof(CustomerData.PurchaseHistory)))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers
        .SdcaLogisticRegression(labelColumnName: "Label", featureColumnName: "Features"))
    .Append(mlContext.Transforms.Conversion
        .MapKeyToValue("PredictedLabel"));

var model = pipeline.Fit(split.TrainSet);

// Evaluate on held-out test set
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

Console.WriteLine("=== Churn Model Metrics ===");
Console.WriteLine($"  AUC:      {metrics.AreaUnderRocCurve:F4}");
Console.WriteLine($"  Accuracy: {metrics.Accuracy:F4}");
Console.WriteLine($"  F1 Score: {metrics.F1Score:F4}");

var modelPath = Path.Combine(AppContext.BaseDirectory, "churn_model.zip");
mlContext.Model.Save(model, data.Schema, modelPath);
Console.WriteLine($"Model saved to {modelPath}");

// --- Web API ---

var builder = WebApplication.CreateBuilder(args);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (
    PredictionEnginePool<CustomerData, ChurnPrediction> pool,
    CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        willChurn = prediction.PredictedLabel,
        probability = prediction.Probability
    });
});

app.Run();

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

